checker_dsl:
EXISTS (`try statement TS`, `integer first`) {
  EXISTS (`integer second`) {
    EXISTS (`exception type masking`, `exception type masked`) {
      AND {
        (`masking is the exception type caught by the catch clause at index first in TS`),
        (`masked is the exception type caught by the catch clause at index second in TS`),
        (`masking is a strict supertype of masked`),
        FORALL (`exception type thrownType`) {
          AND {
            (`thrownType is an exception type that could be thrown from within the block of TS and is not caught inside a nested try statement within TS`),
            (`thrownType and masked share a common descendant in the exception type hierarchy`)
          }
        },
        FORALL (`exception type thrownType`) {
          NOT {
            EXISTS (`exception type priorCaughtType`, `integer priorIdx`) {
              AND {
                (`priorIdx is less than second`),
                (`priorCaughtType is the exception type caught by the catch clause at index priorIdx in TS`),
                (`thrownType is a subtype of priorCaughtType`)
              }
            }
          }
        },
        NOT {
          OR {
            (`masked is a subtype of java.lang.RuntimeException`),
            (`masked is a subtype of java.lang.Error`),
            (`masked is exactly java.lang.Exception`),
            (`masked is exactly java.lang.Throwable`)
          }
        }
      }
    }
  }
}
